import pytest

from your_module import partial  # adjust import as needed


def test_partial_happy_path_positional_and_keyword_args():
    def fn(a, b, c=0, d=0):
        return a, b, c, d

    wrapped = partial(fn, 1, c=3)

    assert wrapped(2, d=4) == (1, 2, 3, 4)


def test_partial_happy_path_no_bound_args():
    def fn(a, b):
        return a + b

    wrapped = partial(fn)

    assert wrapped(2, 3) == 5


def test_partial_merges_kwargs_with_call_kwargs_overriding_bound_kwargs():
    def fn(**kwargs):
        return kwargs

    wrapped = partial(fn, a=1, b=2)

